/* Scroll-to-top floating button */
(function () {
  function ready(fn) {
    if (document.readyState === 'loading') {
      document.addEventListener('DOMContentLoaded', fn);
    } else {
      fn();
    }
  }

  function getScrollTop() {
    var doc = document.documentElement;
    var body = document.body;
    var scrollingEl = document.scrollingElement;
    return Math.max(
      window.scrollY || 0,
      window.pageYOffset || 0,
      (doc && doc.scrollTop) || 0,
      (body && body.scrollTop) || 0,
      (scrollingEl && scrollingEl.scrollTop) || 0
    );
  }

  function getScrollableHeight() {
    var doc = document.documentElement;
    var body = document.body;
    var docH = (doc && doc.scrollHeight) || 0;
    var bodyH = (body && body.scrollHeight) || 0;
    return Math.max(docH, bodyH);
  }

  ready(function () {
    var btn = document.getElementById('scrollTopBtn');

    if (!btn) {
      btn = document.createElement('button');
      btn.id = 'scrollTopBtn';
      btn.className = 'scroll-top';
      btn.type = 'button';
      btn.setAttribute('aria-label', 'Volver arriba');
      btn.setAttribute('title', 'Volver arriba');
      btn.innerHTML = '<span aria-hidden="true">↑</span>';
      document.body.appendChild(btn);
    }

    function setVisible(v) {
      if (v) {
        btn.classList.add('is-visible');
      } else {
        btn.classList.remove('is-visible');
      }
    }

    function onScroll() {
      var scrollTop = getScrollTop();
      setVisible(scrollTop > 180);
    }

    function scrollToTopNow(evt) {
      if (evt) {
        evt.preventDefault();
        evt.stopPropagation();
      }
      try {
        window.scrollTo({ top: 0, behavior: 'smooth' });
      } catch (e) {
        window.scrollTo(0, 0);
      }
      if (document.documentElement) document.documentElement.scrollTop = 0;
      if (document.body) document.body.scrollTop = 0;
    }

    function scheduleUpdate() {
      if (scheduleUpdate._raf) return;
      scheduleUpdate._raf = window.requestAnimationFrame(function () {
        scheduleUpdate._raf = 0;
        onScroll();
      });
    }

    btn.addEventListener('click', scrollToTopNow);
    btn.addEventListener('pointerup', scrollToTopNow);
    btn.addEventListener('touchend', scrollToTopNow, { passive: false });

    document.addEventListener('click', function (evt) {
      var target = evt.target;
      if (!target) return;
      var button = target.closest ? target.closest('#scrollTopBtn') : null;
      if (button) scrollToTopNow(evt);
    }, true);

    window.addEventListener('scroll', scheduleUpdate, { passive: true });
    document.addEventListener('scroll', scheduleUpdate, { passive: true, capture: true });
    window.addEventListener('wheel', scheduleUpdate, { passive: true });
    window.addEventListener('touchmove', scheduleUpdate, { passive: true });
    window.addEventListener('resize', scheduleUpdate, { passive: true });
    window.addEventListener('load', scheduleUpdate);

    if (getScrollableHeight() <= (window.innerHeight + 40)) {
      setVisible(false);
    }

    setTimeout(scheduleUpdate, 0);
    onScroll();
  });
})();